#include <bits/stdc++.h>
using namespace std;
int f[1005],n,m;
set<int> s;
int fa(int x)
{
    if(f[x]==x) return x;
    return f[x]=fa(f[x]);
}
void merge(int x,int y)
{
    int fx=fa(x),fy=fa(y);
    f[fx]=fy;
}
int main()
{

    while(cin>>n)
    {
        if(n==0) break;
        cin>>m;
        for(int i=1;i<=n;i++) f[i]=i;
        while(m--)
        {
            int x,y;
            cin>>x>>y;
            merge(x,y);
        }
        s.clear();
        for(int i=1;i<=n;i++)
        {
            s.insert(fa(i));
        }
        cout<<s.size()-1<<'\n';
    }
    return 0;
}
